1650 /// If we have zero-extended operands of an unsigned div or rem, we may be able
1651 /// to narrow the operation (sink the zext below the math).
1652 static Instruction *narrowUDivURem(BinaryOperator &I,
1653                                    InstCombinerImpl &IC) {
1654   Instruction::BinaryOps Opcode = I.getOpcode();
1655   Value *N = I.getOperand(0);
1656   Value *D = I.getOperand(1);
1657   Type *Ty = I.getType();
1658   Value *X, *Y;
1659   if (match(N, m_ZExt(m_Value(X))) && match(D, m_ZExt(m_Value(Y))) &&
1660       X->getType() == Y->getType() && (N->hasOneUse() || D->hasOneUse())) {
1661     // udiv (zext X), (zext Y) --> zext (udiv X, Y)
1662     // urem (zext X), (zext Y) --> zext (urem X, Y)
1663     Value *NarrowOp = IC.Builder.CreateBinOp(Opcode, X, Y);
1664     return new ZExtInst(NarrowOp, Ty);
1665   }
1666 
1667   Constant *C;
1668   auto &DL = IC.getDataLayout();
1669   if (isa<Instruction>(N) && match(N, m_OneUse(m_ZExt(m_Value(X)))) &&
1670       match(D, m_Constant(C))) {
1671     // If the constant is the same in the smaller type, use the narrow version.
1672     Constant *TruncC = getLosslessUnsignedTrunc(C, X->getType(), DL);
1673     if (!TruncC)
1674       return nullptr;
1675 
1676     // udiv (zext X), C --> zext (udiv X, C')
1677     // urem (zext X), C --> zext (urem X, C')
1678     return new ZExtInst(IC.Builder.CreateBinOp(Opcode, X, TruncC), Ty);
1679   }
1680   if (isa<Instruction>(D) && match(D, m_OneUse(m_ZExt(m_Value(X)))) &&
1681       match(N, m_Constant(C))) {
1682     // If the constant is the same in the smaller type, use the narrow version.
1683     Constant *TruncC = getLosslessUnsignedTrunc(C, X->getType(), DL);
1684     if (!TruncC)
1685       return nullptr;
1686 
1687     // udiv C, (zext X) --> zext (udiv C', X)
1688     // urem C, (zext X) --> zext (urem C', X)
1689     return new ZExtInst(IC.Builder.CreateBinOp(Opcode, TruncC, X), Ty);
