1775 Instruction *InstCombinerImpl::visitSDiv(BinaryOperator &I) {
1776   if (Value *V = simplifySDivInst(I.getOperand(0), I.getOperand(1), I.isExact(),
1777                                   SQ.getWithInstruction(&I)))
1778     return replaceInstUsesWith(I, V);
1779 
1780   if (Instruction *X = foldVectorBinop(I))
1781     return X;
1782 
1783   // Handle the integer div common cases
1784   if (Instruction *Common = commonIDivTransforms(I))
1785     return Common;
1786 
1787   Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1);
1788   Type *Ty = I.getType();
1789   Value *X;
1790   // sdiv Op0, -1 --> -Op0
1791   // sdiv Op0, (sext i1 X) --> -Op0 (because if X is 0, the op is undefined)
1792   if (match(Op1, m_AllOnes()) ||
1793       (match(Op1, m_SExt(m_Value(X))) && X->getType()->isIntOrIntVectorTy(1)))
1794     return BinaryOperator::CreateNSWNeg(Op0);
1795 
1796   // X / INT_MIN --> X == INT_MIN
1797   if (match(Op1, m_SignMask()))
1798     return new ZExtInst(Builder.CreateICmpEQ(Op0, Op1), Ty);
1799 
1800   if (I.isExact()) {
1801     // sdiv exact X, 1<<C --> ashr exact X, C   iff  1<<C  is non-negative
1802     if (match(Op1, m_Power2()) && match(Op1, m_NonNegative())) {
1803       Constant *C = ConstantExpr::getExactLogBase2(cast<Constant>(Op1));
1804       return BinaryOperator::CreateExactAShr(Op0, C);
1805     }
1806 
1807     // sdiv exact X, (1<<ShAmt) --> ashr exact X, ShAmt (if shl is non-negative)
1808     Value *ShAmt;
1809     if (match(Op1, m_NSWShl(m_One(), m_Value(ShAmt))))
1810       return BinaryOperator::CreateExactAShr(Op0, ShAmt);
1811 
1812     // sdiv exact X, -1<<C --> -(ashr exact X, C)
1813     if (match(Op1, m_NegatedPower2())) {
1814       Constant *NegPow2C = ConstantExpr::getNeg(cast<Constant>(Op1));
1815       Constant *C = ConstantExpr::getExactLogBase2(NegPow2C);
1816       Value *Ashr = Builder.CreateAShr(Op0, C, I.getName() + ".neg", true);
